<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Election Alpha Dashboard</title>
    <script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>
    <style>
        :root {
            --bg: #1a1a2e;
            --card: #16213e;
            --text: #e0e0e0;
            --accent: #0f3460;
            --border: #2d4059;
            --success: #4cc9f0;
            --warning: #f72585;
            --danger: #7209b7;
        }

        * {
            box-sizing: border-box;
        }

        body {
            background: var(--bg);
            color: var(--text);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            margin: 0;
            padding: 20px;
            line-height: 1.6;
        }

        header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 30px;
            flex-wrap: wrap;
            gap: 20px;
        }

        h1 {
            margin: 0;
            color: var(--success);
        }

        #last-refresh {
            color: #aaa;
            font-size: 0.9rem;
        }

        .grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(400px, 1fr));
            gap: 25px;
            margin-bottom: 30px;
        }

        .card {
            background: var(--card);
            border-radius: 12px;
            padding: 25px;
            border: 1px solid var(--border);
            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
        }

        h2 {
            margin-top: 0;
            margin-bottom: 20px;
            color: var(--success);
            font-size: 1.3rem;
        }

        select, input {
            background: var(--accent);
            color: var(--text);
            border: 1px solid var(--border);
            border-radius: 6px;
            padding: 8px 12px;
            font-size: 0.9rem;
            margin-bottom: 20px;
        }

        canvas {
            width: 100% !important;
            height: 300px !important;
        }

        table {
            width: 100%;
            border-collapse: collapse;
            margin-top: 10px;
        }

        th, td {
            padding: 12px 15px;
            text-align: left;
            border-bottom: 1px solid var(--border);
        }

        th {
            background: var(--accent);
            cursor: pointer;
            user-select: none;
        }

        th:hover {
            background: #1a365d;
        }

        tr:hover {
            background: rgba(255, 255, 255, 0.05);
        }

        .heatmap-table {
            display: grid;
            overflow-x: auto;
        }

        .heatmap-row {
            display: flex;
        }

        .heatmap-cell {
            flex: 1;
            padding: 8px;
            text-align: center;
            border: 1px solid var(--border);
            min-width: 60px;
        }

        .heatmap-header {
            font-weight: bold;
            background: var(--accent);
        }

        @media (max-width: 768px) {
            .grid {
                grid-template-columns: 1fr;
            }
            .card {
                padding: 15px;
            }
            header {
                flex-direction: column;
                align-items: flex-start;
            }
        }

        .loading {
            text-align: center;
            padding: 20px;
            color: #aaa;
        }

        .refresh-button {
            background: var(--success);
            color: white;
            border: none;
            padding: 8px 16px;
            border-radius: 6px;
            cursor: pointer;
            font-size: 0.9rem;
        }

        .refresh-button:hover {
            opacity: 0.9;
        }
    </style>
</head>
<body>
    <header>
        <h1>Election Alpha Dashboard</h1>
        <div>
            <button class="refresh-button" onclick="refreshAllData()">Refresh Now</button>
            <span id="last-refresh">Last refresh: Never</span>
        </div>
    </header>

    <div class="grid">
        <!-- Panel 1: Price History -->
        <div class="card" id="price-panel">
            <h2>Price History</h2>
            <select id="race-selector">
                <option value="">Loading races...</option>
            </select>
            <div style="position: relative; height: 300px;">
                <canvas id="price-chart"></canvas>
            </div>
        </div>

        <!-- Panel 2: Arbitrage Heatmap -->
        <div class="card" id="arb-panel">
            <h2>Arbitrage Heatmap</h2>
            <div id="arb-heatmap" class="heatmap-table">
                <div class="loading">Loading heatmap...</div>
            </div>
        </div>

        <!-- Panel 3: Alpha Signals -->
        <div class="card" id="alpha-panel">
            <h2>Alpha Signals</h2>
            <div style="position: relative; height: 300px;">
                <canvas id="alpha-chart"></canvas>
            </div>
        </div>

        <!-- Panel 4: Race Summary -->
        <div class="card" id="races-panel">
            <h2>Race Summary</h2>
            <div style="overflow-x: auto;">
                <table id="race-table">
                    <thead>
                        <tr>
                            <th data-sort="race">Race</th>
                            <th data-sort="prob">Latest Probability</th>
                            <th data-sort="delta">24h Δ</th>
                            <th data-sort="platforms">Platforms</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr><td colspan="4" class="loading">Loading race data...</td></tr>
                    </tbody>
                </table>
            </div>
        </div>

        <!-- Panel 5: Weather Correlation -->
        <div class="card" id="weather-panel">
            <h2>Weather-Price Correlation</h2>
            <div style="position: relative; height: 300px;">
                <canvas id="weather-chart"></canvas>
            </div>
        </div>
    </div>

    <script>
        const API_BASE = '/v1/election';
        let charts = {};
        let raceData = [];
        let refreshInterval;

        // Chart color palette
        const CHART_COLORS = {
            polymarket: '#4cc9f0',
            kalshi: '#f72585',
            predictit: '#7209b7',
            manifold: '#4361ee',
            default: '#4ade80'
        };

        // Initialize on page load
        document.addEventListener('DOMContentLoaded', () => {
            initializeCharts();
            loadRaceList();
            refreshAllData();
            startAutoRefresh();
        });

        function initializeCharts() {
            // Price chart
            const priceCtx = document.getElementById('price-chart').getContext('2d');
            charts.price = new Chart(priceCtx, {
                type: 'line',
                data: { datasets: [] },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: { labels: { color: '#e0e0e0' } },
                        tooltip: { mode: 'index', intersect: false }
                    },
                    scales: {
                        x: { 
                            type: 'time',
                            time: { unit: 'hour' },
                            grid: { color: 'rgba(255,255,255,0.1)' },
                            ticks: { color: '#aaa' }
                        },
                        y: {
                            min: 0,
                            max: 1,
                            grid: { color: 'rgba(255,255,255,0.1)' },
                            ticks: { color: '#aaa' }
                        }
                    }
                }
            });

            // Alpha chart
            const alphaCtx = document.getElementById('alpha-chart').getContext('2d');
            charts.alpha = new Chart(alphaCtx, {
                type: 'bar',
                data: { labels: [], datasets: [] },
                options: {
                    indexAxis: 'y',
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: { display: false },
                        tooltip: { mode: 'index', intersect: false }
                    },
                    scales: {
                        x: { 
                            grid: { color: 'rgba(255,255,255,0.1)' },
                            ticks: { color: '#aaa' }
                        },
                        y: {
                            grid: { color: 'rgba(255,255,255,0.1)' },
                            ticks: { color: '#aaa' }
                        }
                    }
                }
            });

            // Weather chart
            const weatherCtx = document.getElementById('weather-chart').getContext('2d');
            charts.weather = new Chart(weatherCtx, {
                type: 'scatter',
                data: { datasets: [] },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: { labels: { color: '#e0e0e0' } },
                        tooltip: {
                            callbacks: {
                                label: (context) => {
                                    const point = context.raw;
                                    return `${point.state}: ${(point.turnout_score * 100).toFixed(1)}% turnout, $${(point.market_price * 100).toFixed(1)} price`;
                                }
                            }
                        }
                    },
                    scales: {
                        x: { 
                            title: { display: true, text: 'Turnout Score', color: '#aaa' },
                            grid: { color: 'rgba(255,255,255,0.1)' },
                            ticks: { color: '#aaa' }
                        },
                        y: {
                            title: { display: true, text: 'Market Price', color: '#aaa' },
                            grid: { color: 'rgba(255,255,255,0.1)' },
                            ticks: { color: '#aaa' }
                        }
                    }
                }
            });
        }

        async function loadRaceList() {
            try {
                const response = await fetch(`${API_BASE}/races`);
                if (response.ok) {
                    const races = await response.json();
                    const selector = document.getElementById('race-selector');
                    selector.innerHTML = '<option value="">Select a race...</option>';

                    races.forEach(race => {
                        const option = document.createElement('option');
                        option.value = race.id;
                        option.textContent = `${race.state} ${race.office} ${race.cycle}`;
                        selector.appendChild(option);
                    });

                    selector.onchange = () => {
                        if (selector.value) {
                            loadPriceHistory(selector.value);
                        }
                    };
                }
            } catch (error) {
                console.error('Failed to load race list:', error);
            }
        }

        async function loadPriceHistory(raceId) {
            try {
                const response = await fetch(`${API_BASE}/chart/price-history/${raceId}?hours=168`);
                const data = await response.json();

                const datasets = [];
                for (const [platform, points] of Object.entries(data.platforms)) {
                    datasets.push({
                        label: platform,
                        data: points.map(p => ({ x: p.ts, y: p.price })),
                        borderColor: CHART_COLORS[platform] || CHART_COLORS.default,
                        backgroundColor: CHART_COLORS[platform] || CHART_COLORS.default,
                        borderWidth: 2,
                        tension: 0.1,
                        fill: false
                    });
                }

                charts.price.data.datasets = datasets;
                charts.price.update();

                // Update race label in chart title
                charts.price.options.plugins.title = {
                    display: true,
                    text: data.race_label,
                    color: '#e0e0e0',
                    font: { size: 14 }
                };
                charts.price.update();
            } catch (error) {
                console.error('Failed to load price history:', error);
            }
        }

        async function loadArbHeatmap() {
            try {
                const response = await fetch(`${API_BASE}/chart/arb-heatmap?cycle=2024`);
                const data = await response.json();

                const container = document.getElementById('arb-heatmap');
                if (!data.races.length || !data.dates.length) {
                    container.innerHTML = '<div class="loading">No arbitrage data available</div>';
                    return;
                }

                let html = '<div class="heatmap-row">';
                html += '<div class="heatmap-cell heatmap-header"></div>';

                // Date headers
                data.dates.forEach(date => {
                    const shortDate = new Date(date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
                    html += `<div class="heatmap-cell heatmap-header" title="${date}">${shortDate}</div>`;
                });
                html += '</div>';

                // Data rows
                data.races.forEach((race, rowIdx) => {
                    html += '<div class="heatmap-row">';
                    html += `<div class="heatmap-cell heatmap-header" title="${race}">${race.substring(0, 12)}${race.length > 12 ? '...' : ''}</div>`;

                    data.matrix[rowIdx].forEach((value, colIdx) => {
                        const color = value === 0 ? 'transparent' : 
                                    value > 2 ? '#4ade80' : 
                                    value > 1 ? '#22c55e' : 
                                    value > 0.5 ? '#16a34a' : '#15803d';
                        const opacity = Math.min(Math.abs(value) / 3, 0.8);
                        html += `<div class="heatmap-cell" title="${race} on ${data.dates[colIdx]}: ${value.toFixed(2)}%" 
                                style="background: ${color}${opacity}; color: ${value > 1 ? 'white' : '#aaa'}">
                                ${value > 0 ? value.toFixed(1) : ''}
                               </div>`;
                    });
                    html += '</div>';
                });

                container.innerHTML = html;
            } catch (error) {
                console.error('Failed to load arb heatmap:', error);
                document.getElementById('arb-heatmap').innerHTML = '<div class="loading">Failed to load heatmap</div>';
            }
        }

        async function loadAlphaSignals() {
            try {
                const response = await fetch(`${API_BASE}/alpha-signals`);
                const signals = await response.json();

                // If no endpoint exists, create mock data for demonstration
                if (!response.ok) {
                    signals = [
                        { race: "PA Senate", predicted_change: 0.05, confidence: 0.8 },
                        { race: "AZ Governor", predicted_change: -0.02, confidence: 0.6 },
                        { race: "MI Senate", predicted_change: 0.03, confidence: 0.9 },
                        { race: "WI Governor", predicted_change: 0.01, confidence: 0.7 },
                        { race: "GA Senate", predicted_change: -0.04, confidence: 0.5 }
                    ];
                }

                const labels = signals.map(s => s.race);
                const data = signals.map(s => s.predicted_change);
                const confidences = signals.map(s => s.confidence);

                charts.alpha.data.labels = labels;
                charts.alpha.data.datasets = [{
                    label: 'Predicted Probability Change',
                    data: data,
                    backgroundColor: confidences.map(c => 
                        c > 0.8 ? '#4cc9f0' : 
                        c > 0.6 ? '#4361ee' : 
                        c > 0.4 ? '#7209b7' : '#f72585'
                    ),
                    borderColor: '#0f3460',
                    borderWidth: 1
                }];

                charts.alpha.update();
            } catch (error) {
                console.error('Failed to load alpha signals:', error);
            }
        }

        async function loadRaceSummary() {
            try {
                const response = await fetch(`${API_BASE}/races`);
                const races = await response.json();
                raceData = races;

                const tbody = document.querySelector('#race-table tbody');
                tbody.innerHTML = '';

                races.forEach(race => {
                    const row = document.createElement('tr');

                    const delta = race.latest_probability - (race.previous_probability || race.latest_probability);
                    const deltaClass = delta > 0 ? 'positive' : delta < 0 ? 'negative' : '';

                    row.innerHTML = `
                        <td>${escapeHtml(`${race.state} ${race.office}`)}</td>
                        <td>${(race.latest_probability * 100).toFixed(1)}%</td>
                        <td class="${deltaClass}">${delta > 0 ? '+' : ''}${(delta * 100).toFixed(1)}%</td>
                        <td>${race.platform_count || 2}</td>
                    `;

                    tbody.appendChild(row);
                });

                // Add sorting functionality
                document.querySelectorAll('#race-table th').forEach(th => {
                    th.addEventListener('click', () => {
                        const sortBy = th.dataset.sort;
                        sortRaceTable(sortBy);
                    });
                });
            } catch (error) {
                console.error('Failed to load race summary:', error);
            }
        }

        function sortRaceTable(sortBy) {
            if (!raceData.length) return;

            const tbody = document.querySelector('#race-table tbody');
            const rows = Array.from(tbody.rows);

            rows.sort((a, b) => {
                const aVal = a.cells[['race', 'prob', 'delta', 'platforms'].indexOf(sortBy)].textContent;
                const bVal = b.cells[['race', 'prob', 'delta', 'platforms'].indexOf(sortBy)].textContent;

                if (sortBy === 'race') return aVal.localeCompare(bVal);
                if (sortBy === 'delta') {
                    const aNum = parseFloat(aVal.replace('%', ''));
                    const bNum = parseFloat(bVal.replace('%', ''));
                    return bNum - aNum; // Sort by magnitude
                }
                const aNum = parseFloat(aVal);
                const bNum = parseFloat(bVal);
                return bNum - aNum;
            });

            // Reorder rows
            rows.forEach(row => tbody.appendChild(row));
        }

        async function loadWeatherScatter() {
            try {
                const response = await fetch(`${API_BASE}/chart/weather-scatter/2024`);
                const data = await response.json();

                if (!data.length) {
                    charts.weather.data.datasets = [];
                    charts.weather.update();
                    return;
                }

                // Group by state for different colors
                const states = [...new Set(data.map(d => d.state))];
                const datasets = states.map(state => {
                    const stateData = data.filter(d => d.state === state);
                    return {
                        label: state,
                        data: stateData.map(d => ({
                            x: d.turnout_score,
                            y: d.market_price,
                            state: d.state,
                            race_label: d.race_label
                        })),
                        backgroundColor: CHART_COLORS[state.toLowerCase()] || CHART_COLORS.default,
                        borderColor: '#0f3460',
                        borderWidth: 1,
                        pointRadius: 8
                    };
                });

                charts.weather.data.datasets = datasets;
                charts.weather.update();
            } catch (error) {
                console.error('Failed to load weather scatter:', error);
            }
        }

        async function refreshAllData() {
            try {
                await Promise.allSettled([
                    loadArbHeatmap(),
                    loadAlphaSignals(),
                    loadRaceSummary(),
                    loadWeatherScatter()
                ]);

                // Update last refresh time
                const now = new Date();
                document.getElementById('last-refresh').textContent = 
                    `Last refresh: ${now.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`;
            } catch (error) {
                console.error('Failed to refresh data:', error);
            }
        }

        function startAutoRefresh() {
            if (refreshInterval) clearInterval(refreshInterval);
            refreshInterval = setInterval(refreshAllData, 60000); // 60 seconds
        }

        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }
